local function assert_eq(a, b, msg) if a ~= b then error((msg or "assert_eq failed") .. ": " .. tostring(a) .. " ~= " .. tostring(b), 2) end end
local function assert_true(x, msg) if not x then error(msg or "assert_true failed", 2) end end

local function hex_to_buf(hex)
  local n = #hex / 2
  local buf = ffi.new("uint8_t[?]", n)
  local i = 0
  for pair in hex:gmatch("%x%x") do buf[i] = tonumber(pair, 16); i = i + 1 end
  return buf, n
end

local function write_i64(buf, off, v)
  local n = tonumber(v)
  local neg = n < 0
  if neg then n = -n end
  local bytes = {}
  for i = 0, 7 do
    bytes[i] = n % 256
    n = math.floor(n / 256)
  end
  if neg then
    local carry = 1
    for i = 0, 7 do
      local x = 255 - bytes[i] + carry
      if x >= 256 then x = x - 256; carry = 1 else carry = 0 end
      bytes[i] = x
    end
  end
  for i = 0, 7 do buf[off + i] = bytes[i] end
end

local function read_i64(stack, slot)
  return tonumber(ffi.cast("int64_t *", stack)[(slot or 0) * 2])
end

local function read_f64(stack, slot)
  return tonumber(ffi.cast("double *", stack)[(slot or 0) * 2])
end

local function f64_bytes_from_int(value)
  local n = tonumber(value) or 0
  if n == 0 then return {0, 0, 0, 0, 0, 0, 0, 0} end
  local sign = 0
  if n < 0 then sign = 0x80000000; n = -n end
  local exp = math.floor(math.log(n) / math.log(2))
  local pow = 2 ^ exp
  local mant = math.floor((n / pow - 1) * 2 ^ 52 + 0.5)
  local lo = mant % 4294967296
  local hi = sign + (exp + 1023) * 1048576 + math.floor(mant / 4294967296)
  return {
    lo % 256, math.floor(lo / 256) % 256, math.floor(lo / 65536) % 256, math.floor(lo / 16777216) % 256,
    hi % 256, math.floor(hi / 256) % 256, math.floor(hi / 65536) % 256, math.floor(hi / 16777216) % 256,
  }
end

local function write_f64_from_int(buf, off, v)
  local b = f64_bytes_from_int(v)
  for i = 0, 7 do buf[off + i] = b[i + 1] end
end

local function patch_immediates(buf, f, op)
  for _, dr in ipairs(f.data_relocs or {}) do
    if dr.reloc_kind == "abs64" and dr.role_kind == "imm" then
      local v = op.sbx or op.sBx or op.c or op.b or 0
      if op.op == "LOADF" then write_f64_from_int(buf, dr.code_offset, v) else write_i64(buf, dr.code_offset, v) end
    end
  end
end

local function patch_const_i64(buf, f, value)
  for _, dr in ipairs(f.data_relocs or {}) do
    if dr.reloc_kind == "abs64" and dr.role_kind == "const" then write_i64(buf, dr.code_offset, value) end
  end
end

local function patch_payloads(buf, f, payload)
  payload = payload or {}
  for _, dr in ipairs(f.data_relocs or {}) do
    local v = payload[dr.role_kind]
    if (dr.role_kind == "slot" or dr.role_kind == "slot_store") and payload.slots then
      local actual = payload.slots[tonumber(dr.role_arg) or 0]
      if actual ~= nil then v = tonumber(actual) * 16 end
    end
    if v ~= nil then
      v = tonumber(v) + (tonumber(dr.addend) or 0)
      if dr.reloc_kind == "abs8" then buf[dr.code_offset] = v % 256
      elseif dr.reloc_kind == "abs32" or dr.reloc_kind == "abs32s" then
        local n = v
        if n < 0 then n = n + 4294967296 end
        buf[dr.code_offset] = n % 256
        buf[dr.code_offset + 1] = math.floor(n / 256) % 256
        buf[dr.code_offset + 2] = math.floor(n / 65536) % 256
        buf[dr.code_offset + 3] = math.floor(n / 16777216) % 256
      elseif dr.reloc_kind == "abs64" then write_i64(buf, dr.code_offset, v)
      end
    end
  end
end

local function ptr_u64(p)
  return ffi.cast("uint64_t", ffi.cast("uintptr_t", p))
end

local function executable_copy(buf, n)
  local PROT_READ, PROT_WRITE, PROT_EXEC = 1, 2, 4
  local MAP_PRIVATE, MAP_ANON = 2, 0x20
  local mem = ffi.C.mmap(nil, n, PROT_READ + PROT_WRITE + PROT_EXEC, MAP_PRIVATE + MAP_ANON, -1, 0)
  assert_true(mem ~= ffi.cast("void *", -1), "mmap failed")
  ffi.C.memcpy(mem, buf, n)
  return mem
end

local function lower_native(ops, facts)
  local r = SSA.compile(ops, facts or {})
  assert_true(r.ok, table.concat(r.errors or {}, "\n"))
  local fr = StencilLower.generate(r, { facts = facts or {} })
  assert_true(fr.ok, table.concat(fr.errors or {}, "\n"))
  assert_true(fr.stencil.executable == true and (fr.stencil.code_size or 0) > 0, "native stencil expected")
  return fr.stencil
end

