local function assert_eq(a, b, msg) if a ~= b then error((msg or "assert_eq failed") .. ": " .. tostring(a) .. " ~= " .. tostring(b), 2) end end
local function assert_true(x, msg) if not x then error(msg or "assert_true failed", 2) end end

local bank_path = "experiments/lua_interpreter_vm/spongejit/build/sponbank/libsponbank.so"
do
  local f = io.open(bank_path, "rb")
  assert_true(f ~= nil, "missing generated L1 bank: run cd experiments/lua_interpreter_vm/spongejit && make stencils && make bank")
  if f then f:close() end
end

local bank = ffi.load(bank_path)
assert_true(bank.spon_bank_stencil_count() > 0, "empty stencil bank")
assert_true(bank.spon_bank_pattern_count() > 0, "empty pattern bank")

local function bytes_to_hex(p, n)
  local out = {}
  for i = 0, n - 1 do out[#out + 1] = string.format("%02x", tonumber(p[i])) end
  return table.concat(out)
end

local function c_data_relocs(id)
  local n = ffi.new("uint32_t[1]")
  local p = bank.spon_stencil_data_relocs(id, n)
  local out = {}
  for i = 0, tonumber(n[0]) - 1 do
    out[#out + 1] = {
      code_offset = tonumber(p[i].code_offset),
      reloc_kind = tonumber(p[i].reloc_kind),
      role_kind = tonumber(p[i].role_kind),
      op_idx = tonumber(p[i].op_idx),
      role_arg = tonumber(p[i].role_arg),
      addend = tonumber(p[i].addend),
    }
  end
  return out
end

local function c_control_relocs(id)
  local n = ffi.new("uint32_t[1]")
  local p = bank.spon_stencil_control_relocs(id, n)
  local out = {}
  for i = 0, tonumber(n[0]) - 1 do
    out[#out + 1] = {
      code_offset = tonumber(p[i].code_offset),
      reloc_kind = tonumber(p[i].reloc_kind),
      edge_kind = tonumber(p[i].edge_kind),
      endpoint_index = tonumber(p[i].endpoint_index),
      target_delta = tonumber(p[i].target_delta),
    }
  end
  return out
end

local function from_bank(id)
  local d = bank.spon_get_stencil(id)
  assert_true(d ~= nil, "missing stencil descriptor " .. tostring(id))
  assert_true(bit.band(tonumber(d.flags), 10) == 10, "selected stencil is not exact native: " .. tostring(id))
  assert_true(tonumber(d.size) > 0, "selected stencil has no native bytes: " .. tostring(id))
  local data = bank.spon_stencil_data(id)
  assert_true(data ~= nil, "spon_stencil_data returned NULL: " .. tostring(id))
  return {
    stencil_id = tonumber(d.stencil_id),
    executable = true,
    flags = tonumber(d.flags),
    code_size = tonumber(d.size),
    code_hex = bytes_to_hex(data, tonumber(d.size)),
    data_relocs = c_data_relocs(id),
    control_relocs = c_control_relocs(id),
  }
end

local function has_edge(st, edge_kind)
  for _, cr in ipairs(st.control_relocs or {}) do if cr.edge_kind == edge_kind then return true end end
  return false
end

local function read_i64(stack, slot)
  return tonumber(ffi.cast("int64_t *", stack)[(slot or 0) * 2])
end

local function read_f64(stack, slot)
  return tonumber(ffi.cast("double *", stack)[(slot or 0) * 2])
end

local function ptr_u64(p)
  return ffi.cast("uint64_t", ffi.cast("uintptr_t", p))
end

local function sig_u64(facts)
  local sig = Sig.encode(facts)
  return ffi.new("uint64_t", sig.hi or 0) * 0x100000000ULL + ffi.new("uint64_t", sig.lo or 0)
end

