local function actual_slot_entries(ops)
  local xs = {}
  for pc, op in ipairs(ops or {}) do
    for field, kind in pairs(FIELD_KIND) do
      local slot = op[field]
      if slot == nil and op.op == "SELF" and field == "aux" and tonumber(op.a) then slot = tonumber(op.a) + 1 end
      if slot ~= nil and tonumber(slot) then
        xs[#xs + 1] = { op_idx = pc - 1, logical_slot = tonumber(slot), field_kind = kind }
      end
    end
  end
  local arr = ffi.new("SponSlotMapEntry[?]", #xs)
  for i, x in ipairs(xs) do
    arr[i - 1].op_idx = x.op_idx
    arr[i - 1].logical_slot = x.logical_slot
    arr[i - 1].field_kind = x.field_kind
  end
  return arr, #xs
end

